sql:
SELECT name
FROM bowlers
ORDER BY name ASC;

SELECT bowler_id, matches, overs, wickets
FROM bowler_stats
WHERE matches > 5;

SELECT bowler_id, AVG(average) AS avg_average, AVG(economy) AS avg_economy
FROM bowling_performances
GROUP BY bowler_id;

SELECT SUM(matches) AS total_matches_played
FROM bowler_stats
WHERE season_id = 0;

external_knowledge:
- Top bowlers refer to those with the highest total wickets and lowest average bowling performance (i.e., the best performance is indicated by a lower average bowling number); 
- The rankings are specific to season 1; 
- Bowling average is an indicator of a bowler's performance, with lower averages generally indicating better performance.
